     2→import { Panel, PanelGroup, PanelResizeHandle } from 'react-resizable-panels';
     3→import {
     4→  Plus,
     5→  Play,
     6→  Brain,
     7→  Terminal as TerminalIcon,
     8→  Check,
     9→  Loader2,
    10→  Sparkles,
    11→  ArrowRight,
    12→  X,
    13→  Minus,
    14→  Maximize2,
    15→  RefreshCw,
    16→  Wifi,
    17→  WifiOff,
    18→  FolderOpen,
    19→  Pencil,
    20→  MoreVertical,
    21→  ChevronRight,
    22→  ChevronLeft,
    23→} from 'lucide-react';
    24→import { api } from '../../stores/app';
    25→import { ChatInput, type UploadedFile } from './ChatInput';
    26→
    27→// ============================================================================
    28→// TYPES
    29→// ============================================================================
    30→
    31→const API_URL = 'http://localhost:3333';
    32→const WS_URL = 'ws://localhost:3333/events';
    33→
    34→type AgentStatus = 'ready' | 'busy' | 'offline';
    35→type TerminalLineType = 'prompt' | 'thinking' | 'tool_call' | 'tool_result' | 'output' | 'error' | 'info' | 'command' | 'system';
    36→
    37→interface Agent {
    38→  id: string;
    39→  name: string;
    40→  status: AgentStatus;
    41→  icon: string;
    42→  type: 'claude-code' | 'openclaw';
    43→}
    44→
    45→interface PlanStep {
    46→  id: string;
    47→  text: string;
    48→  agent: string | null;
    49→  status?: 'pending' | 'running' | 'completed' | 'failed';
    50→  source?: 'plan' | 'extracted' | 'manual';
    51→  threadId?: string;
    52→  turnId?: string;
    53→  costUsd?: number;
    54→  durationMs?: number;
    55→}
    56→
    57→interface TerminalLine {
    58→  id: string;
    59→  type: TerminalLineType;
    60→  content: string;
    61→  timestamp?: string;
    62→  isStreaming?: boolean;
    63→  /** Block index for tool_call lines (used to match input_json_delta updates) */
    64→  blockIndex?: number;
    65→}
    66→
    67→interface TerminalState {
    68→  id: string;
    69→  agent: Agent;
    70→  lines: TerminalLine[];
    71→  isStreaming: boolean;
    72→  currentTask?: string;
    73→  /** Plan step id when this terminal is executing a step (for status/cost sync) */
    74→  currentStepId?: string;
    75→  path?: string; // Override workspace path
    76→  // Thread integration (Phase 2/3)
    77→  threadId?: string;
    78→  sessionActive?: boolean;
    79→}
    80→
    81→interface MinimizedWidget {
    82→  id: string;
    83→  type: 'terminal' | 'tasks';
    84→  title: string;
    85→  icon: string;
    86→  data?: TerminalState;
    87→}
    88→
    89→// ============================================================================
    90→// UTILITIES
    91→// ============================================================================
    92→
    93→function makeTimestamp(): string {
    94→  return new Date().toLocaleTimeString('en-US', { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });
    95→}
    96→
    97→function getAgentIcon(agent: { type: string; name: string }): string {
    98→  if (agent.type === 'claude-code') return '🖥️';
    99→  const name = agent.name.toLowerCase();
   100→  if (name.includes('scout')) return '🔍';
   101→  if (name.includes('forge')) return '🔨';
   102→  if (name.includes('vera')) return '✨';
   103→  if (name.includes('echo')) return '📢';
   104→  return '🤖';
