   107→/** Extract human-readable detail (path, command, etc.) from tool input JSON (full or partial) */
   108→function tryExtractToolDetail(json: string): string | undefined {
   109→  try {
   110→    const input = JSON.parse(json);
   111→    if (input.path) return input.path;
   112→    if (input.file_path) return input.file_path;
   113→    if (input.file) return input.file;
   114→    if (input.command) {
   115→      const cmd = String(input.command);
   116→      return cmd.length > 60 ? cmd.slice(0, 57) + '...' : cmd;
   117→    }
   118→    if (input.pattern) return input.pattern;
   119→    if (input.query) return input.query;
   120→    if (input.regex) return input.regex;
   121→    return undefined;
   122→  } catch {
   123→    const pathMatch = json.match(/"(?:path|file_path|file)"\s*:\s*"([^"]+)"/);
   124→    if (pathMatch) return pathMatch[1];
   125→    const cmdMatch = json.match(/"command"\s*:\s*"([^"]{1,60})/);
   126→    if (cmdMatch) return cmdMatch[1] + (json.includes(cmdMatch[0] + '"') ? '' : '...');
   127→    return undefined;
   128→  }
   129→}
   130→
   131→/** Heuristic: extract task-like lines from assistant output (numbered list, "Next steps:", etc.) */
   132→function extractTasksFromText(text: string, maxTasks = 10): string[] {
   133→  if (!text || typeof text !== 'string') return [];
   134→  const lines = text.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
   135→  const tasks: string[] = [];
   136→  let inList = false;
   137→  const numberBullet = /^\d+[.)]\s*(.+)$/;
   138→  const dashBullet = /^[-*]\s+(.+)$/;
   139→
   140→  for (const line of lines) {
   141→    const numbered = line.match(numberBullet);
   142→    if (numbered) {
   143→      inList = true;
   144→      tasks.push(numbered[1].trim());
   145→      continue;
   146→    }
   147→    const dashed = line.match(dashBullet);
   148→    if (dashed && inList) {
   149→      tasks.push(dashed[1].trim());
   150→      continue;
   151→    }
   152→    if (/^(next steps?|to do|i will|we can|tasks?):?\s*$/i.test(line)) {
   153→      inList = true;
   154→      continue;
   155→    }
   156→    inList = false;
   157→  }
   158→
   159→  const result = tasks.slice(0, maxTasks).filter(t => t.length > 2);
   160→  // If no list found but we have substantial text, use first line as a single summary task
   161→  if (result.length === 0 && text.trim().length > 10) {
   162→    const first = lines[0];
   163→    if (first && first.length > 5 && first.length < 200) result.push(first);
   164→  }
   165→  return result;
   166→}
   167→
   168→/** Renders step text with markdown-like formatting: **bold** and `code` (as badges for paths/handlers) */
   169→function PlanStepText({ text }: { text: string }) {
   170→  const parts: React.ReactNode[] = [];
   171→  const regex = /(\*\*[^*]+\*\*|`[^`]+`)/g;
   172→  let lastIndex = 0;
   173→  let match;
   174→  let key = 0;
   175→  while ((match = regex.exec(text)) !== null) {
   176→    if (match.index > lastIndex) {
   177→      parts.push(<span key={`t-${key++}`}>{text.slice(lastIndex, match.index)}</span>);
   178→    }
   179→    const segment = match[1];
   180→    if (segment.startsWith('**') && segment.endsWith('**')) {
   181→      parts.push(<strong key={`t-${key++}`} className="font-semibold text-zinc-100">{segment.slice(2, -2)}</strong>);
   182→    } else if (segment.startsWith('`') && segment.endsWith('`')) {
   183→      const code = segment.slice(1, -1);
   184→      const isPath = /[/\\]|\.(ts|tsx|js|jsx|md|json|py)(:\d+)?$|:\d+\)?$/.test(code) || code.includes(':');
   185→      parts.push(
   186→        <span
   187→          key={`t-${key++}`}
   188→          className={isPath ? 'inline-flex items-center px-1.5 py-0.5 rounded bg-zinc-700/80 text-amber-200/90 font-mono text-[0.85em]' : 'px-1 py-0.5 rounded bg-zinc-800 text-zinc-200 font-mono text-[0.9em]'}
   189→        >
   190→          {code}
   191→        </span>
   192→      );
   193→    }
   194→    lastIndex = regex.lastIndex;
   195→  }
   196→  if (lastIndex < text.length) {
   197→    parts.push(<span key={`t-${key++}`}>{text.slice(lastIndex)}</span>);
   198→  }
   199→  return <span className="text-sm text-zinc-200 leading-snug">{parts.length > 0 ? parts : text}</span>;
   200→}
