   689→  /** Accumulate tool input JSON per block index (for input_json_delta) */
   690→  const toolInputByBlockRef = useRef<Record<number, string>>({});
   691→
   692→  // Fetch agents on mount
   693→  const fetchAgents = useCallback(async () => {
