   735→  }, [fetchAgents]);
   736→
   737→  const handleWsEvent = useCallback((data: any) => {
   738→    if (data.type !== 'event') return;
   739→    const event = data.event;
   740→    if (!event) return;
   741→
   742→    // Support both adapterId (legacy) and threadId (Phase 2/3)
   743→    const adapterId = event.adapterId;
   744→    const threadId = event.threadId;
   745→    
   746→    // For thread events, find terminal by threadId
   747→    const findTerminal = (terminals: TerminalState[]) => {
   748→      if (threadId) {
   749→        return terminals.find(t => t.threadId === threadId);
   750→      }
   751→      if (adapterId) {
   752→        return terminals.find(t => t.agent.id === adapterId);
   753→      }
   754→      return null;
   755→    };
   756→
   757→    const matchesTerminal = (t: TerminalState) => {
   758→      if (threadId) return t.threadId === threadId;
   759→      if (adapterId) return t.agent.id === adapterId;
   760→      return false;
   761→    };
   762→
   763→    if (!adapterId && !threadId) return;
   764→
   765→    console.log('[WS Event]', event.type, { adapterId, threadId }, event.payload);
   766→
   767→    // Handle session.message (raw SDK events from thread)
   768→    if (event.type === 'session.message' && event.payload) {
   769→      const msg = event.payload;
   770→      
   771→      // Process SDK message types for thread sessions
   772→      if (msg.type === 'stream_event') {
   773→        const streamEvent = msg.event;
   774→        const blockIndex = streamEvent?.index;
   775→
   776→        // content_block_start: thinking or tool_use → add terminal line
   777→        if (streamEvent?.type === 'content_block_start') {
   778→          const block = streamEvent.content_block;
   779→          const blockType = block?.type;
   780→          const blockId = block?.id ?? `block_${blockIndex ?? 0}`;
   781→
   782→          if (blockType === 'thinking') {
   783→            const line: TerminalLine = {
   784→              id: `thinking-${blockId}`,
   785→              type: 'thinking',
   786→              content: 'Thinking...',
   787→              timestamp: makeTimestamp(),
   788→              isStreaming: true,
   789→            };
   790→            setTerminals(prev => prev.map(t =>
   791→              matchesTerminal(t) ? { ...t, lines: [...t.lines, line], isStreaming: true } : t
   792→            ));
   793→          } else if (blockType === 'tool_use' || blockType === 'server_tool_use') {
   794→            const toolName = block?.name ?? 'Tool';
   795→            const idx = blockIndex ?? 0;
   796→            toolInputByBlockRef.current[idx] = '';
   797→            const line: TerminalLine = {
   798→              id: `tool-${blockId}`,
   799→              type: 'tool_call',
   800→              content: toolName,
   801→              timestamp: makeTimestamp(),
   802→              isStreaming: true,
   803→              blockIndex: idx,
   804→            };
   805→            setTerminals(prev => prev.map(t =>
   806→              matchesTerminal(t) ? { ...t, lines: [...t.lines, line], isStreaming: true } : t
   807→            ));
   808→          }
   809→        }
   810→
   811→        // content_block_delta: text_delta, thinking_delta, or input_json_delta
   812→        if (streamEvent?.type === 'content_block_delta') {
   813→          const delta = streamEvent.delta;
   814→          const deltaType = delta?.type;
   815→
   816→          if (deltaType === 'text_delta' && delta.text) {
   817→            // Append text delta to terminal output
   818→            setTerminals(prev => prev.map(t => {
   819→              if (!matchesTerminal(t)) return t;
   820→              const lastLine = t.lines[t.lines.length - 1];
   821→              if (lastLine?.type === 'output' && lastLine.isStreaming) {
   822→                return {
   823→                  ...t,
   824→                  lines: t.lines.map((l, i) =>
   825→                    i === t.lines.length - 1
   826→                      ? { ...l, content: l.content + delta.text }
   827→                      : l
   828→                  ),
   829→                };
   830→              }
   831→              return {
   832→                ...t,
   833→                lines: [...t.lines, {
   834→                  id: `${Date.now()}`,
   835→                  type: 'output' as const,
   836→                  content: delta.text,
   837→                  timestamp: makeTimestamp(),
   838→                  isStreaming: true,
   839→                }],
   840→              };
   841→            }));
   842→          } else if (deltaType === 'thinking_delta' && delta.thinking) {
   843→            // Append to last thinking line or create one
   844→            setTerminals(prev => prev.map(t => {
   845→              if (!matchesTerminal(t)) return t;
   846→              let idx = -1;
   847→              for (let i = t.lines.length - 1; i >= 0; i--) {
   848→                if (t.lines[i].type === 'thinking') {
   849→                  idx = i;
   850→                  break;
   851→                }
   852→              }
   853→              if (idx >= 0) {
   854→                return {
   855→                  ...t,
   856→                  lines: t.lines.map((l, i) =>
   857→                    i === idx
   858→                      ? { ...l, content: l.content + delta.thinking, isStreaming: true }
   859→                      : l
   860→                  ),
   861→                  isStreaming: true,
   862→                };
   863→              }
   864→              return {
   865→                ...t,
   866→                lines: [...t.lines, {
   867→                  id: `thinking-${Date.now()}`,
   868→                  type: 'thinking' as const,
   869→                  content: delta.thinking,
   870→                  timestamp: makeTimestamp(),
   871→                  isStreaming: true,
   872→                }],
   873→                isStreaming: true,
   874→              };
   875→            }));
   876→          } else if (deltaType === 'input_json_delta' && delta.partial_json != null) {
   877→            // Accumulate tool input JSON and update tool_call line with human-readable detail
   878→            const blockIdx = streamEvent?.index;
   879→            if (typeof blockIdx === 'number') {
   880→              const acc = (toolInputByBlockRef.current[blockIdx] || '') + delta.partial_json;
   881→              toolInputByBlockRef.current[blockIdx] = acc;
   882→              const detail = tryExtractToolDetail(acc);
   883→              if (detail != null) {
   884→                setTerminals(prev => prev.map(t => {
   885→                  if (!matchesTerminal(t)) return t;
   886→                  const lineIdx = t.lines.findIndex(
   887→                    (l) => l.type === 'tool_call' && l.blockIndex === blockIdx
   888→                  );
   889→                  if (lineIdx < 0) return t;
   890→                  const line = t.lines[lineIdx];
   891→                  const baseContent = line.content.includes(': ') ? line.content.split(': ')[0] : line.content;
   892→                  return {
   893→                    ...t,
   894→                    lines: t.lines.map((l, i) =>
   895→                      i === lineIdx ? { ...l, content: `${baseContent}: ${detail}` } : l
   896→                    ),
   897→                  };
   898→                }));
   899→              }
   900→            }
   901→          }
   902→        }
   903→      }
   904→      return;
   905→    }
   906→
   907→    if (event.type === 'activity' && event.payload) {
   908→      const activityType = event.payload.activityType;
   909→      const lineType: TerminalLineType = 
   910→        activityType === 'thinking' ? 'thinking' :
   911→        activityType === 'file_read' ? 'tool_call' :
   912→        activityType === 'file_write' ? 'tool_call' :
   913→        activityType === 'command' ? 'command' : 'info';
   914→
   915→      const line: TerminalLine = {
   916→        id: `${Date.now()}-${Math.random()}`,
   917→        type: lineType,
   918→        content: event.payload.label + (event.payload.detail ? `: ${event.payload.detail}` : ''),
   919→        timestamp: makeTimestamp(),
   920→        isStreaming: event.payload.status === 'running',
   921→      };
   922→
   923→      setTerminals(prev => prev.map(t =>
   924→        matchesTerminal(t) ? { 
   925→          ...t, 
   926→          lines: [...t.lines, line],
   927→          isStreaming: event.payload.status === 'running',
   928→        } : t
   929→      ));
   930→    }
   931→
   932→    if (event.type === 'content.delta' && event.payload?.delta) {
   933→      // Append to last output line or create new one
   934→      setTerminals(prev => prev.map(t => {
   935→        if (!matchesTerminal(t)) return t;
   936→        
   937→        const lastLine = t.lines[t.lines.length - 1];
   938→        if (lastLine?.type === 'output' && lastLine.isStreaming) {
   939→          // Append to existing streaming output
   940→          return {
   941→            ...t,
   942→            lines: t.lines.map((l, i) => 
   943→              i === t.lines.length - 1 
   944→                ? { ...l, content: l.content + event.payload.delta }
   945→                : l
   946→            ),
   947→          };
   948→        } else {
   949→          // Create new output line
   950→          return {
   951→            ...t,
   952→            lines: [...t.lines, {
   953→              id: `${Date.now()}`,
   954→              type: 'output' as const,
   955→              content: event.payload.delta,
   956→              timestamp: makeTimestamp(),
   957→              isStreaming: true,
   958→            }],
   959→          };
   960→        }
   961→      }));
   962→    }
   963→
   964→    // Handle turn/item completion: update terminal streaming state and sync plan step + cost
   965→    if (event.type === 'turn.completed' || event.type === 'item.completed') {
   966→      if (event.type === 'turn.completed') toolInputByBlockRef.current = {};
   967→      const matchedTerminal = terminalsRef.current.find(matchesTerminal);
   968→      const stepIdToComplete = matchedTerminal?.currentStepId;
   969→      const usage = event.type === 'turn.completed' ? event.payload?.usage : undefined;
   970→
   971→      setTerminals(prev => prev.map(t =>
   972→        !matchesTerminal(t) ? t : {
   973→          ...t,
   974→          isStreaming: false,
   975→          currentStepId: undefined,
   976→          lines: t.lines.map(l => ({ ...l, isStreaming: false })),
   977→        }
   978→      ));
   979→
   980→      if (stepIdToComplete && usage) {
   981→        setPlanSteps(prev => prev.map(s =>
   982→          s.id === stepIdToComplete
   983→            ? { ...s, status: 'completed' as const, costUsd: usage.costUsd ?? s.costUsd }
   984→            : s
   985→        ));
   986→      }
   987→
   988→      // Extract suggested tasks from assistant result and merge as unassigned steps
   989→      if (event.type === 'turn.completed' && event.payload?.result) {
   990→        const extracted = extractTasksFromText(event.payload.result);
   991→        if (extracted.length > 0) {
   992→          setPlanSteps(prev => {
   993→            const existingNormalized = new Set(prev.map(s => s.text.trim().toLowerCase()));
   994→            const newSteps: PlanStep[] = extracted
   995→              .filter(t => {
   996→                const n = t.trim().toLowerCase();
   997→                if (existingNormalized.has(n)) return false;
   998→                existingNormalized.add(n);
   999→                return true;
  1000→              })
  1001→              .map((text, i) => ({
  1002→                id: `step-extracted-${Date.now()}-${i}`,
  1003→                text: text.trim(),
  1004→                agent: null as string | null,
  1005→                status: 'pending' as const,
  1006→                source: 'extracted' as const,
  1007→              }));
  1008→            return prev.length === 0 && newSteps.length > 0 ? newSteps : [...prev, ...newSteps];
  1009→          });
  1010→        }
  1011→      }
  1012→    }
  1013→  }, []);
  1014→
  1015→  // WebSocket connection for streaming events
  1016→  useEffect(() => {
  1017→    console.log('[WS] Connecting to', WS_URL);
  1018→    const ws = new WebSocket(WS_URL);
  1019→    wsRef.current = ws;
  1020→
  1021→    ws.onopen = () => console.log('[WS] Connected');
  1022→    
  1023→    ws.onmessage = (e) => {
  1024→      try {
  1025→        const data = JSON.parse(e.data);
  1026→        handleWsEvent(data);
  1027→      } catch (err) {
  1028→        console.error('[WS] Parse error:', err);
  1029→      }
  1030→    };
  1031→
  1032→    ws.onerror = (e) => console.warn('[WS] Error:', e);
  1033→    ws.onclose = () => console.warn('[WS] Closed');
  1034→
  1035→    return () => ws.close();
  1036→  }, [handleWsEvent]);
  1037→
  1038→  // Terminal handlers
  1039→  const handleNewTerminal = (agentId?: string) => {
  1040→    const agent = agents.find(a => a.id === agentId) || agents[0];
  1041→    if (!agent) return;
  1042→
  1043→    setTerminals(prev => [...prev, {
  1044→      id: `terminal-${Date.now()}`,
  1045→      agent,
  1046→      lines: [{ id: `${Date.now()}`, type: 'system', content: `Session started — ${agent.name}`, timestamp: makeTimestamp() }],
  1047→      isStreaming: false,
  1048→    }]);
  1049→  };
  1050→
  1051→  const handleCloseTerminal = async (terminalId: string) => {
  1052→    const terminal = terminals.find(t => t.id === terminalId);
  1053→    
  1054→    // Close thread session if exists
  1055→    if (terminal?.threadId) {
  1056→      try {
  1057→        await fetch(`${API_URL}/threads/${terminal.threadId}/close`, { method: 'POST' });
  1058→      } catch (err) {
  1059→        console.warn('Failed to close thread session:', err);
  1060→      }
  1061→    }
  1062→    
  1063→    setTerminals(prev => prev.filter(t => t.id !== terminalId));
  1064→  };
  1065→
  1066→  const handleMinimizeTerminal = (terminal: TerminalState) => {
  1067→    setMinimizedWidgets(prev => [...prev, { id: terminal.id, type: 'terminal', title: terminal.agent.name, icon: terminal.agent.icon, data: terminal }]);
  1068→    setTerminals(prev => prev.filter(t => t.id !== terminal.id));
  1069→  };
  1070→
  1071→  const handleTerminalMessage = async (terminalId: string, message: string, files?: UploadedFile[]) => {
  1072→    const terminal = terminals.find(t => t.id === terminalId);
  1073→    if (!terminal) return;
  1074→
  1075→    const cwd = terminal.path || workspacePath || (typeof process !== 'undefined' && typeof process.cwd === 'function' ? process.cwd() : null) || '/';
  1076→
  1077→    // Build prompt content with file info
  1078→    let promptContent = message;
  1079→    if (files && files.length > 0) {
  1080→      const fileNames = files.map(f => f.name).join(', ');
  1081→      promptContent = `${message}\n📎 Attached: ${fileNames}`;
  1082→    }
  1083→
  1084→    // Add prompt line and extract current task into plan widget (so it shows and syncs on completion)
  1085→    const extractedStepId = `step-extracted-${Date.now()}`;
  1086→    setPlanSteps(prev => [...prev, {
  1087→      id: extractedStepId,
  1088→      text: message,
  1089→      agent: terminal.agent.id,
  1090→      status: 'running',
  1091→      source: 'extracted',
  1092→    }]);
  1093→    setTerminals(prev => prev.map(t =>
  1094→      t.id === terminalId ? {
  1095→        ...t,
  1096→        isStreaming: true,
  1097→        currentTask: message,
  1098→        currentStepId: extractedStepId,
  1099→        lines: [...t.lines, { id: `${Date.now()}`, type: 'prompt', content: promptContent, timestamp: makeTimestamp() }]
  1100→      } : t
  1101→    ));
  1102→
  1103→    try {
  1104→      let threadId = terminal.threadId;
  1105→
  1106→      // Create thread/session if needed (Phase 2/3)
  1107→      if (!threadId) {
  1108→        threadId = `thread-${terminalId}`;
  1109→        const sessionRes = await fetch(`${API_URL}/threads/${threadId}/session`, {
  1110→          method: 'POST',
  1111→          headers: { 'Content-Type': 'application/json' },
  1112→          body: JSON.stringify({ 
  1113→            cwd,
  1114→            name: `${terminal.agent.name} - ${new Date().toLocaleString()}`,
  1115→          }),
  1116→        });
  1117→        const sessionData = await sessionRes.json();
  1118→        
  1119→        if (!sessionData.ok) {
  1120→          throw new Error(sessionData.error || 'Failed to create session');
  1121→        }
  1122→        setTerminals(prev => prev.map(t =>
  1123→          t.id === terminalId ? { ...t, threadId, sessionActive: true, currentStepId: extractedStepId } : t
  1124→        ));
  1125→      }
  1126→
  1127→      // Send via thread API (persistent session)
  1128→      let res = await fetch(`${API_URL}/threads/${threadId}/send`, {
  1129→        method: 'POST',
  1130→        headers: { 'Content-Type': 'application/json' },
  1131→        body: JSON.stringify({ message }),
  1132→      });
  1133→      let data = await res.json();
  1134→
  1135→      // If server restarted, session is gone; create session and retry send once
  1136→      if (!data.ok && data.error === 'No active session for thread' && terminal.threadId) {
  1137→        setTerminals(prev => prev.map(t =>
  1138→          t.id === terminalId ? { ...t, threadId: undefined, sessionActive: false } : t
  1139→        ));
  1140→        const sessionRes = await fetch(`${API_URL}/threads/${threadId}/session`, {
  1141→          method: 'POST',
  1142→          headers: { 'Content-Type': 'application/json' },
  1143→          body: JSON.stringify({ cwd, name: `${terminal.agent.name} - ${new Date().toLocaleString()}` }),
  1144→        });
  1145→        const sessionData = await sessionRes.json();
  1146→        if (!sessionData.ok) throw new Error(sessionData.error || 'Failed to create session');
  1147→        setTerminals(prev => prev.map(t =>
  1148→          t.id === terminalId ? { ...t, threadId, sessionActive: true } : t
  1149→        ));
  1150→        res = await fetch(`${API_URL}/threads/${threadId}/send`, {
