  1171→      setPlanSteps(prev => prev.map(s =>
  1172→        s.id === extractedStepId ? { ...s, status: 'failed' as const } : s
  1173→      ));
  1174→    }
  1175→  };
  1176→
  1177→  const handleSendStepToTerminal = (step: PlanStep, terminalId?: string) => {
  1178→    const agent = step.agent ? agents.find(a => a.id === step.agent) : agents[0];
  1179→    if (!agent) return;
  1180→
