        {terminal.lines.map((line) => (
          <TerminalLineItem key={line.id} line={line} />
        ))}
      </div>

      {/* Input */}
      <div className="flex-shrink-0 p-2 border-t border-zinc-800">
        <ChatInput
          onSend={handleSend}
          placeholder="Send message..."
          disabled={terminal.isStreaming}
          showPrompt={true}
          promptIcon="❯"
        />
      </div>
    </div>
  );
}

